// Pull both ensures-conjuncts into the proof context so the two `forall|lo,hi|`
// triggers line up across the two runs (run-1 binds post1_self_.gap, run-2
// binds post2_self_.gap; without re-instantiation z3 never matches them).
assert(post1_self_@ == pre_self_@.insert(k, v));
assert(post2_self_@ == pre_self_@.insert(k, v));
assert(forall |lo, hi| post1_self_.gap(lo, hi) <==>
                pre_self_.gap(lo, hi)
            && !(lo.lt_spec(KeyIterator::new_spec(k))
              && KeyIterator::new_spec(k).lt_spec(hi)));
assert(forall |lo, hi| post2_self_.gap(lo, hi) <==>
                pre_self_.gap(lo, hi)
            && !(lo.lt_spec(KeyIterator::new_spec(k))
              && KeyIterator::new_spec(k).lt_spec(hi)));

// Map equality on `@` is transitive through the common insert RHS.
assert(post1_self_@ == post2_self_@);

// Pointwise: both gaps reduce to the same predicate on (pre_self_, k).
assert(forall |lo: KeyIterator<K>, hi: KeyIterator<K>|
    post1_self_.gap(lo, hi) <==> post2_self_.gap(lo, hi));
